import{_ as d,c as e,a,o as i}from"./app-CEcM0piI.js";const s={};function r(l,t){return i(),e("div",null,t[0]||(t[0]=[a(`<p>HyperText Markup Language超文本标记语言, 是一种用于创建网页的标准标记语言。</p><p>任何标签都可以在首标签结尾加上一个/表示标签已闭合,单标签就是这样实现的 <code>&lt;a/&gt;</code>和<code>&lt;a&gt;&lt;/a&gt;</code>相同</p><h2 id="特殊标签" tabindex="-1"><a class="header-anchor" href="#特殊标签"><span>特殊标签</span></a></h2><h4 id="文档类型声明标签" tabindex="-1"><a class="header-anchor" href="#文档类型声明标签"><span>文档类型声明标签</span></a></h4><p>声明该文档使用哪种版本的html显示网页</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;!DOCTYPE html&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="注释标签" tabindex="-1"><a class="header-anchor" href="#注释标签"><span>注释标签</span></a></h4><p>ctrl+/</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;!--注释语句--&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="单标签" tabindex="-1"><a class="header-anchor" href="#单标签"><span>单标签</span></a></h2><table><thead><tr><th>标签</th><th>写法</th><th>介绍</th><th>属性</th></tr></thead><tbody><tr><td></td><td><code>&lt;meta&gt;</code></td><td>写在头标签中包含文档的所有内容</td><td>charset: 字符集，规定HTML文档应使用哪种编码方式</td></tr><tr><td>换行标签</td><td><code>&lt;br /&gt;</code></td><td>break打断，换行。从标签处开始强制换行，跟段落不一样不会有间距</td><td></td></tr><tr><td>图像标签和路径</td><td><code>&lt;img/&gt;</code></td><td>image图像. 图像标签必须拥有src属性</td><td>src: 图片路径或网址<br>alt: 替换文本,图像不能显示时显示的文字<br>title: 提示文本，光标放到图像上时显示的文字<br>width: 设置图像的宽度,同时高度也等比例缩放<br>height: 设置图像的高度,同时宽度也等比例缩放<br>border: 设置图像的边框粗细</td></tr><tr><td>表单控件</td><td><code>&lt;input /&gt;</code></td><td>输入，包含type属性，根据不同type属性值，有多种输入形式</td><td>type: <br>radio: 单选按钮同样可以选择多个，若想实现单选同属的多个radio输入须有相同的name属性<br>name: 定义input元素的名称,要求单选按钮和复选框要有相同的name值<br>value: 规定input元素的值<br>checked: 规定此input元素默认选中的项<br>maxlength: 规定输入字段中字符的最大长度</td></tr><tr><td></td><td><code>&lt;hr&gt;</code></td><td>水平线标签</td><td></td></tr></tbody></table><h2 id="双标签" tabindex="-1"><a class="header-anchor" href="#双标签"><span>双标签</span></a></h2><ul><li>关系:</li></ul><ol><li>包含关系</li><li>并列关系</li></ol><ul><li>属性 一个标签可以有多个属性，必须写在头标签里面 属性之间不分先后顺序，标签名和属性，属性和属性之间用空格间隔 属性采用键值对的格式key=“value”</li></ul><table><thead><tr><th>标签</th><th>写法</th><th>介绍</th><th>属性</th></tr></thead><tbody><tr><td>根标签</td><td><code>&lt;html&gt;&lt;/html&gt;</code></td><td>除了文档声明标签其他所有标签都要写在根标签中</td><td>lang: languages缩写，定义当前文档显示的语言，en为英语，zh-CN为中文，即使定义了语言文档依然可以显示其他语言(对浏览器和搜索引擎有用)</td></tr><tr><td>头标签</td><td></td><td>文档的头部head标签中必须设置的标签，显示在网页的工作栏</td><td></td></tr><tr><td>主体标签</td><td><code>&lt;body&gt;&lt;/body&gt;</code></td><td>包含文档的所有内容</td><td></td></tr><tr><td>标题标签</td><td><code>&lt;title&gt;&lt;/title&gt;</code></td><td>写在头标签中,其中的内容显示在浏览器的工作栏中</td><td></td></tr><tr><td>段落标签</td><td><code>&lt;p&gt;&lt;/p&gt;</code></td><td>paragraph段落，将文档中的文字分为若干段落，每个&lt;p&gt;标签中包含的文字为一段每个段落之间有空隙</td><td></td></tr><tr><td>加粗</td><td><code>&lt;strong&gt;&lt;/strong&gt;</code>或<code>&lt;b&gt;&lt;/b&gt;</code></td><td>文本格式化标签</td><td></td></tr><tr><td>倾斜</td><td><code>&lt;em&gt;&lt;/em&gt;</code>或<code>&lt;i&gt;&lt;/i&gt;</code></td><td>文本格式化标签</td><td></td></tr><tr><td>删除线</td><td><code>&lt;del&gt;&lt;/del&gt;</code>或<code>&lt;s&gt;&lt;/s&gt;</code></td><td>文本格式化标签</td><td></td></tr><tr><td>下划线</td><td><code>&lt;ins&gt;&lt;/ins&gt;</code>或<code>&lt;u&gt;&lt;/u&gt;</code></td><td>文本格式化标签</td><td></td></tr><tr><td>盒子</td><td><code>&lt;div&gt;&lt;/div&gt;</code></td><td>包装布局标签division分割，分区 ( 独占一行 )</td><td></td></tr><tr><td>盒子</td><td><code>&lt;span&gt;&lt;/span&gt;</code></td><td>包装布局标签span跨度，跨距 ( 一行中可以有多个 )</td><td></td></tr><tr><td>超链接标签</td><td><code>&lt;a&gt;&lt;/a&gt;</code></td><td>超链接</td><td>href: 可以是网页元素链接,外部链接,内部链接,下载链接,锚点链接,目标位置,空链接等<br>target: 决定超链接的网站是在原页面打开还是新页面打开，默认在原页面打开_self原页面打开_blank新页面打开</td></tr><tr><td>表格标签</td><td><code>&lt;table&gt;&lt;/table&gt;</code></td><td>定义表格</td><td></td></tr><tr><td>表格头标签</td><td><code>&lt;thead&gt;&lt;/thead&gt;</code></td><td>定义表格的头部，必须拥有&lt;tr&gt;标签，一般位于第一行</td><td></td></tr><tr><td>表格主题标签</td><td><code>&lt;tbody&gt;&lt;/tbody&gt;</code></td><td>定义表格的主体，主要用于存放数据本体</td><td></td></tr><tr><td></td><td><code>&lt;th&gt;&lt;/th&gt;</code></td><td>定义表头</td><td></td></tr><tr><td></td><td><code>&lt;tr&gt;&lt;/tr&gt;</code></td><td>定义表格中的行</td><td>rowspan: 跨行合并（纵向）最上侧单元格为目标单元格，填入数字表示合并数量<br>colspan:跨列合并（横向）最左侧单元格为目标单元格，填入数字表示合并数量</td></tr><tr><td></td><td><code>&lt;td&gt;&lt;/td&gt;</code></td><td>table data定义表格中的单元格</td><td>align:规定表格相对周围元素的对齐方式left,center,right<br>border: 规定表格单元是否有边框，默认为空，表示没边框，1表示有边框<br>cellpadding: 规定单元边沿与其内容之间的空白，默认1像素<br>cellspacing: 规定单元格之间的空白，默认2像素<br>width: 规定表格的宽度<br>height: 规定表格的高度</td></tr><tr><td>列表标签</td><td><code>&lt;ul&gt;&lt;/ul&gt;</code></td><td>无序列表各个列表项之间没有顺序级别之分，是并列的,会带有自己的样式属性（列表项前有圆点）可通过css更改</td><td></td></tr><tr><td>有序列表</td><td><code>&lt;ol&gt;&lt;/ol&gt;</code></td><td>有自己的样式属性（列表项前有序号）</td><td></td></tr><tr><td>列表项</td><td><code>&lt;li&gt;&lt;/li&gt;</code></td><td>对于有序列表和无序列表适用</td><td></td></tr><tr><td>自定义列表</td><td><code>&lt;dl&gt;&lt;/dl&gt;</code></td><td>只能包含&lt;dt&gt;&lt;dd&gt;一个&lt;dt&gt;可对应多个&lt;dd&gt;</td><td></td></tr><tr><td></td><td><code>&lt;dt&gt;&lt;/dt&gt;</code></td><td>定义自定义列表的项目，名字</td><td></td></tr><tr><td></td><td><code>&lt;dd&gt;&lt;/dd&gt;</code></td><td>描述每一个项目，名字</td><td></td></tr><tr><td>表单标签</td><td><code>&lt;form&gt;&lt;/form&gt;</code></td><td>表单域</td><td>action:填入url地址，用于指定接收并处理表单数据的服务器程序的url地址<br>method:用于设置表单数据的提交方式，取值为get或post<br>name: 名称,用于指定表单的名称，以区分同一页面中的多个表单域</td></tr><tr><td>列表标签</td><td><code>&lt;ul&gt;&lt;/ul&gt;</code></td><td>无序列表各个列表项之间没有顺序级别之分，是并列的,会带有自己的样式属性（列表项前有圆点）可通过css更改</td><td></td></tr><tr><td>有序列表</td><td><code>&lt;ol&gt;&lt;/ol&gt;</code></td><td>有自己的样式属性（列表项前有序号）</td><td></td></tr><tr><td>列表项</td><td><code>&lt;li&gt;&lt;/li&gt;</code></td><td>对于有序列表和无序列表适用</td><td></td></tr><tr><td>自定义列表</td><td><code>&lt;dl&gt;&lt;/dl&gt;</code></td><td>只能包含&lt;dt&gt;&lt;dd&gt;一个&lt;dt&gt;可对应多个&lt;dd&gt;</td><td></td></tr><tr><td></td><td><code>&lt;dt&gt;&lt;/dt&gt;</code></td><td>定义自定义列表的项目，名字</td><td></td></tr><tr><td></td><td><code>&lt;dd&gt;&lt;/dd&gt;</code></td><td>描述每一个项目，名字</td><td></td></tr><tr><td>表单标签</td><td><code>&lt;form&gt;&lt;/form&gt;</code></td><td>表单域</td><td>action:填入url地址，用于指定接收并处理表单数据的服务器程序的url地址<br>method:用于设置表单数据的提交方式，取值为get或post<br>name: 名称,用于指定表单的名称，以区分同一页面中的多个表单域</td></tr><tr><td>下拉列表标签</td><td><code>&lt;select&gt;&lt;/select&gt;</code></td><td>定义下拉列表至少要包含一个&lt;option标签&gt;</td><td></td></tr><tr><td></td><td><code>&lt;option&gt;&lt;/option&gt;</code></td><td></td><td>selected: 定义默认选中项</td></tr><tr><td>文本<br>框标签</td><td><code>&lt;textarea&gt;&lt;/textarea&gt;</code></td><td>定义文本框</td><td>rows: 显示的行数<br>cols: 每行中的字符数</td></tr><tr><td></td><td><code>&lt;label&gt;&lt;/label&gt;</code></td><td>为input元素定义标注,用于绑定一个表单元素,当点击<code>&lt;label&gt;</code>标签内的文本时，浏览器就会自动将焦点（光标转到或者选择对应的表单元素上,用来增加用户体验</td><td>for: 该属性需要绑定到一个表单标签的label属性,从而实现二者同步</td></tr></tbody></table><p>空链接<code>#</code></p><p>锚点链接链接的是本网页相关herf属性的位置 链接文本:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;a href=&quot;#名字&quot;&gt;文字&lt;/a&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>目标位置</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;标签 id=&quot;#名字&quot;&gt;文字&lt;/标签&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>表单控件的属性</p><table><thead><tr><th>属性值</th><th>描述</th></tr></thead><tbody><tr><td>button</td><td>定义可点击按钮（多数情况下，用于通过JavaScript启动脚本）</td></tr><tr><td>checkbox</td><td>定义复选框。</td></tr><tr><td>file</td><td>定义输入字段和“浏览“按钮，供文件上传。</td></tr><tr><td>hidden</td><td>定义隐藏的输入字段。</td></tr><tr><td>image</td><td>定义图像形式的提交按钮。</td></tr><tr><td>password</td><td>定义密码字段。该字段中的字符被掩码。</td></tr><tr><td>radio</td><td>定义单选按钮。</td></tr><tr><td>reset</td><td>定义单选按钮定义重置按钮。重置按钮会清除表单中的所有数据。</td></tr><tr><td>submit</td><td>定义提交按钮。提交按钮会把表单数据发送到服务器。</td></tr><tr><td>text</td><td>定义单行的输入字段，用户可在其中输入文本。默认宽度为20个字符。</td></tr></tbody></table><table><thead><tr><th>特殊字符</th><th>描述</th><th>字符的代码</th></tr></thead><tbody><tr><td> </td><td>空格符</td><td>&amp;nbsp;</td></tr><tr><td>&lt;</td><td>小于号</td><td>&amp;lt;</td></tr><tr><td>&gt;</td><td>大于号</td><td>&amp;gt;</td></tr><tr><td>&amp;</td><td>and号</td><td>&amp;amp;</td></tr><tr><td>¥</td><td>人民币符</td><td>&amp;yen;</td></tr><tr><td>©</td><td>版权</td><td>&amp;copy;</td></tr><tr><td>®</td><td>注册商标</td><td>&amp;reg;</td></tr><tr><td>°</td><td>摄氏度</td><td>&amp;deg;</td></tr><tr><td>±</td><td>正负号</td><td>&amp;plusmn;</td></tr><tr><td>×</td><td>乘号</td><td>&amp;times;</td></tr><tr><td>÷</td><td>除号</td><td>&amp;divide;</td></tr><tr><td>²</td><td>平方（上标2）</td><td>&amp;sup2;</td></tr><tr><td>³</td><td>立方（上标3）</td><td>&amp;sup3;</td></tr><tr><td></td><td></td><td></td></tr></tbody></table><h1 id="html5" tabindex="-1"><a class="header-anchor" href="#html5"><span>html5</span></a></h1><p>这些新特性都有兼容性问题，基本是E9+以上版本的浏览器才支持，如果不考虑兼容性问题，可以大量使用这些新特性。</p><h1 id="标签" tabindex="-1"><a class="header-anchor" href="#标签"><span>标签</span></a></h1><h2 id="语义化标签" tabindex="-1"><a class="header-anchor" href="#语义化标签"><span>语义化标签</span></a></h2><ul><li><code>&lt;header&gt;</code>：头部标签</li><li><code>&lt;nav&gt;</code>：导航标签</li><li><code>&lt;article&gt;</code>：内容标签</li><li><code>&lt;section&gt;</code>：定义文档某个区域</li><li><code>&lt;aside&gt;</code>：侧边栏标签</li><li><code>&lt;footer&gt;</code>：尾部标签 ![[Clip_2024-10-08_13-28-07.png]]</li></ul><p>这种语义化标准主要是针对搜索引擎的 这些新标签页面中可以使用多次 在IE9中，需要把这些元素转换为块级元素 移动端更喜欢使用这些标签</p><h2 id="多媒体标签" tabindex="-1"><a class="header-anchor" href="#多媒体标签"><span>多媒体标签</span></a></h2><ol><li>音频：<code>&lt;audio&gt;</code></li><li>视频：<code>&lt;video&gt;</code> 使用它们可以很方便的在页面中嵌入音频和视频，而不再去使用flash和其他浏览器插件。</li></ol><h3 id="video" tabindex="-1"><a class="header-anchor" href="#video"><span>video</span></a></h3><p>当前<code>\\&lt;video&gt;</code>元素支持三种视频格式：尽量使用mp4格式</p><table><thead><tr><th>浏览器</th><th>MP4</th><th>Ogg</th><th>WebM</th></tr></thead><tbody><tr><td>Internet Explorer</td><td>YES</td><td>NO</td><td>NO</td></tr><tr><td>Chrome</td><td>YES</td><td>YES</td><td>YES</td></tr><tr><td>Firefox</td><td>YES<br>从Firefox21版本开始Linux系统从Firefox30开始</td><td>YES</td><td>YES</td></tr><tr><td>Safari</td><td>YES</td><td>NO</td><td>NO</td></tr><tr><td>Opera</td><td>YES从Opera25版本开始</td><td>YES</td><td>YES</td></tr></tbody></table><p>使用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;video src=&quot;视频文件路径&quot;&gt;&lt;/video&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>先查看是否支持mp4格式若支持只显示video.mp4若不支持再查看是否支持ogg,若都不支持显示&quot;您的浏览器不支持video标签。&quot;</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>    &lt;video width=&quot;320&quot; height=&quot;240&quot; controls&gt;</span></span>
<span class="line"><span>        &lt;source src=&quot;movie.mp4&quot; type=&quot;video/mp4&quot;&gt;</span></span>
<span class="line"><span>        &lt;source src=&quot;movie.ogg&quot; type=&quot;video/ogg&quot;&gt;</span></span>
<span class="line"><span>        您的浏览器不支持video标签。</span></span>
<span class="line"><span>    &lt;/video&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th>属性</th><th>值</th><th>描述</th></tr></thead><tbody><tr><td>autoplay</td><td>autoplay</td><td>视频就绪自动播放（谷歌浏览器需要添加muted来解决自动播放问题）</td></tr><tr><td>controls</td><td>controls</td><td>向用户显示播放控件</td></tr><tr><td>width</td><td>pixels(像素)</td><td>设置播放器宽度</td></tr><tr><td>height</td><td>pixels(像素)</td><td>设置播放器高度</td></tr><tr><td>loop</td><td>loop</td><td>播放完是否继续播放该视频，循环播放</td></tr><tr><td>preload</td><td>auto（预先加载视频）<br>none (不应加载视频)</td><td>规定是否预加载视频（如果有了autoplay就忽略该属性)</td></tr><tr><td>src</td><td>url</td><td>视频url地址</td></tr><tr><td>poster</td><td>Imgurl</td><td>加载等待的画面图片</td></tr><tr><td>muted</td><td>muted</td><td>静音播放<br></td></tr></tbody></table><h3 id="audio" tabindex="-1"><a class="header-anchor" href="#audio"><span>audio</span></a></h3><table><thead><tr><th>浏览器</th><th>MP3</th><th>Wav</th><th>Ogg</th></tr></thead><tbody><tr><td>Internet Explorer</td><td>YES</td><td>NO</td><td>NO</td></tr><tr><td>Chrome</td><td>YES</td><td>YES</td><td>YES</td></tr><tr><td>Firefox</td><td>YES</td><td>YES</td><td>YES</td></tr><tr><td>Safari</td><td>YES</td><td>YES</td><td>NO</td></tr><tr><td>Opera</td><td>YES</td><td>YES</td><td>YES</td></tr></tbody></table><p>语法:</p><div class="language-html line-numbers-mode" data-highlighter="shiki" data-ext="html" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span style="--shiki-light:#999999;--shiki-dark:#666666;">&lt;</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">audio</span><span style="--shiki-light:#B07D48;--shiki-dark:#BD976A;"> src</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">=</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">文件地址</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#B07D48;--shiki-dark:#BD976A;"> controls</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">=</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">controls</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&gt;&lt;/</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">audio</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>    &lt;audio controls&gt;</span></span>
<span class="line"><span>        &lt;source src=&quot;horse.ogg&quot; type=&quot;audio/ogg&quot;&gt;</span></span>
<span class="line"><span>        &lt;source src=&quot;horse.mp3&quot; type=&quot;audio/mpeg&quot;&gt;</span></span>
<span class="line"><span>        您的浏览器不支持audiq元素。</span></span>
<span class="line"><span>    &lt;/audio&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th>属性</th><th>值</th><th>描述</th></tr></thead><tbody><tr><td>autoplay</td><td>autoplay</td><td>如果出现该属性，则音频在就绪后马上播放。chrome浏览器禁用了,没有解决方案,只能通过js控制</td></tr><tr><td>controls</td><td>controls</td><td>如果出现该属性，则向用户显示控件，比如播放按钮。</td></tr><tr><td>loop</td><td>loop</td><td>如果出现该属性，则每当音频结束时重新开始播放。</td></tr><tr><td>src</td><td>url</td><td>要播放的音频的URL。</td></tr><tr><td></td><td></td><td></td></tr></tbody></table><h1 id="input类型" tabindex="-1"><a class="header-anchor" href="#input类型"><span>input类型</span></a></h1><table><thead><tr><th>属性值</th><th>说明</th></tr></thead><tbody><tr><td>type=&quot;email&quot;</td><td>限制用户输入必须为Email类型</td></tr><tr><td>type=&quot;url&quot;</td><td>限制用户输入必须为URL类型</td></tr><tr><td>type=&quot;date&quot;</td><td>限制用户输入必须为日期类型</td></tr><tr><td>type=&quot;time&quot;</td><td>限制用户输入必须为时间类型</td></tr><tr><td>type=&quot;month&quot;</td><td>限制用户输入必须为月类型</td></tr><tr><td>type=&quot;week&quot;</td><td>限制用户输入必须为周类型</td></tr><tr><td>type=&quot;number&quot;</td><td>限制用户输入必须为数字类型</td></tr><tr><td>type=&quot;tel&quot;</td><td>手机号码</td></tr><tr><td>type=&quot;search&quot;</td><td>搜索框</td></tr><tr><td>type=&quot;color&quot;</td><td>生成一个颜色选择表单</td></tr></tbody></table><h2 id="表单属性" tabindex="-1"><a class="header-anchor" href="#表单属性"><span>表单属性</span></a></h2><table><thead><tr><th>属性</th><th>值</th><th>说明</th></tr></thead><tbody><tr><td>required</td><td>required</td><td>表单拥有该属性表示其内容不能为空，必填可以使用选择器单独控制内容的属性</td></tr><tr><td>placeholder</td><td>提示文本</td><td>表单的提示信息，存在默认值将不显示可以使用选择器单独控制其内容的属性</td></tr><tr><td>autofocus</td><td>autofocus</td><td>自动聚焦属性，页面加载完成自动聚焦到指定表单</td></tr><tr><td>autocomplete</td><td>off /on</td><td>当用户在字段开始键入时，浏览器基于之前键入过的值，应该显示出在字段中填写的选项。默认已经打开，如autocomplete=&quot;on&quot;，关闭autocomplete=&quot;off&quot;需要放在表单内，同时加上name属性，同时成功提交</td></tr><tr><td>multiple</td><td>multiple</td><td>可以多选文件提交</td></tr></tbody></table><h1 id="svg" tabindex="-1"><a class="header-anchor" href="#svg"><span>SVG</span></a></h1><p>SVG标签是SVG图形的一个容器,它与普通的图像不同,普通的图像是描述像素的,svg是使用类似xml语言的格式描述图形的</p><p>svg标签内包含了很多子标签用于绘制各种图形 svg类似于一个画布 width属性定义svg的宽度,height定义svg的高度</p><h2 id="内置图形" tabindex="-1"><a class="header-anchor" href="#内置图形"><span>内置图形</span></a></h2><p><code>&lt;rect/&gt;</code>标签用于定义矩形 圆形circle 椭圆ellipse</p><table><thead><tr><th>属性</th><th>说明</th></tr></thead><tbody><tr><td>width</td><td>定义矩形的宽度。</td></tr><tr><td>height</td><td>定义矩形的高度。</td></tr><tr><td>fill</td><td>定义矩形的填充颜色。</td></tr><tr><td>stroke-width</td><td>定义了矩形的边框宽度。</td></tr><tr><td>stroke</td><td>定义矩形边框的颜色。</td></tr></tbody></table><h2 id="线条" tabindex="-1"><a class="header-anchor" href="#线条"><span>线条</span></a></h2><p>线条line</p><p>x1,y1属性表示起始点的坐标,x2,y2表示终止点的坐标</p><h2 id="多线条" tabindex="-1"><a class="header-anchor" href="#多线条"><span>多线条</span></a></h2><p>多线条通过points属性绘制给出折点的坐标</p><h2 id="多边形polygon" tabindex="-1"><a class="header-anchor" href="#多边形polygon"><span>多边形polygon</span></a></h2><p>多边形需要使用points属性描述图形的顶点,有几个角就给出几个坐标</p><h2 id="文本text" tabindex="-1"><a class="header-anchor" href="#文本text"><span>文本text</span></a></h2><p>在svg中也可以使用text标签绘制文本,这样就可以使用svg的方法控制文本了</p><p>在svg中的文本上也可以使用a标签包裹添加链接,推荐使用target属性添加链接 如果使用href属性添加链接需要引入,这是因为svg是使用xml语言实现的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;svg xmlns:xlink=&quot;http://www.w3.0rg/1999/xlink&quot;&gt;</span></span>
<span class="line"><span>	&lt;a xlink:href=&quot;&quot; target=&quot;&quot;&gt;</span></span>
<span class="line"><span>		&lt;text&gt; &lt;/text&gt;</span></span>
<span class="line"><span>	&lt;/a&gt;</span></span>
<span class="line"><span>&lt;/svg&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>xlink是w3c的网址,只是固定写法无需深究</p><h2 id="路径path" tabindex="-1"><a class="header-anchor" href="#路径path"><span>路径path</span></a></h2><p>使用<code>&lt;path/&gt;</code>标签定义 在d属性中指明命令,d是draw的缩写</p><p>d属性有多个命令:</p><ul><li>M命令 : moveto的缩写,定义绘制图形的起点坐标<code>&lt;path d=&quot;M150 0/&gt;</code></li><li>L命令 : lineto的缩写,定义线条的绘制即终点坐标<code>l75 200</code></li><li>q命令 : 用于绘制贝塞尔曲线 命令中点的坐标不需要使用逗号分隔是使用空格分隔 两个命令的坐标定位是不同的,m是绝对定位,是相对于屏幕坐标的定位,l是相对定位,是相对于m的定位</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;path d=&quot;M 100 350 q 150 -300 300 0&quot; /&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>![[Pasted image 20241024133151.png]]</p><h2 id="描边属性" tabindex="-1"><a class="header-anchor" href="#描边属性"><span>描边属性</span></a></h2><p>svg提供了许多描边属性 stroke笔画属性 stroke-width笔画宽度属性 stroke-linecapL笔画笔帽属性 stroke-dasharray虚线笔画属性</p>`,76)]))}const h=d(s,[["render",r]]),o=JSON.parse('{"path":"/front/html/1/","title":"HTML","lang":"zh-CN","frontmatter":{"title":"HTML","createTime":"2025/06/18 21:05:22","permalink":"/front/html/1/"},"readingTime":{"minutes":12.18,"words":3653},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/html/HTML.md","headers":[]}');export{h as comp,o as data};
